(self.webpackChunk=self.webpackChunk||[]).push([[275],{924:(e,n,s)=>{"use strict";s.r(n),s.d(n,{data:()=>a});const a={key:"v-0217a3a0",path:"/docker/docker-compose-command.html",title:"docker-compose指令",lang:"en-US",frontmatter:{title:"docker-compose指令"},excerpt:"",headers:[{level:2,title:"build",slug:"build",children:[]},{level:2,title:"cap_add, cap_drop",slug:"cap-add-cap-drop",children:[]},{level:2,title:"command",slug:"command",children:[]},{level:2,title:"configs",slug:"configs",children:[]},{level:2,title:"cgroup_parent",slug:"cgroup-parent",children:[]},{level:2,title:"container_name",slug:"container-name",children:[]},{level:2,title:"deploy",slug:"deploy",children:[]},{level:2,title:"devices",slug:"devices",children:[]},{level:2,title:"depends_on",slug:"depends-on",children:[]},{level:2,title:"dns",slug:"dns",children:[]},{level:2,title:"dns_search",slug:"dns-search",children:[]},{level:2,title:"tmpfs",slug:"tmpfs",children:[]},{level:2,title:"env_file",slug:"env-file",children:[]},{level:2,title:"environment",slug:"environment",children:[]},{level:2,title:"expose",slug:"expose",children:[]},{level:2,title:"external_links",slug:"external-links",children:[]},{level:2,title:"extra_hosts",slug:"extra-hosts",children:[]},{level:2,title:"healthcheck",slug:"healthcheck",children:[]},{level:2,title:"image",slug:"image",children:[]},{level:2,title:"labels",slug:"labels",children:[]},{level:2,title:"links",slug:"links",children:[]},{level:2,title:"logging",slug:"logging",children:[]},{level:2,title:"network_mode",slug:"network-mode",children:[]},{level:2,title:"networks",slug:"networks",children:[]},{level:2,title:"pid",slug:"pid",children:[]},{level:2,title:"ports",slug:"ports",children:[]},{level:2,title:"secrets",slug:"secrets",children:[]},{level:2,title:"security_opt",slug:"security-opt",children:[]},{level:2,title:"stop_signal",slug:"stop-signal",children:[]},{level:2,title:"sysctls",slug:"sysctls",children:[]},{level:2,title:"ulimits",slug:"ulimits",children:[]},{level:2,title:"volumes",slug:"volumes",children:[]},{level:2,title:"其它指令",slug:"其它指令",children:[]},{level:2,title:"读取变量",slug:"读取变量",children:[]},{level:2,title:"常用软件docker-compose文件",slug:"常用软件docker-compose文件",children:[{level:3,title:"Tomcat",slug:"tomcat",children:[]},{level:3,title:"Mysql5",slug:"mysql5",children:[]},{level:3,title:"Mysql8",slug:"mysql8",children:[]},{level:3,title:"Redis集群",slug:"redis集群",children:[]},{level:3,title:"Sentinel集群",slug:"sentinel集群",children:[]},{level:3,title:"Jenkins",slug:"jenkins",children:[]}]}],filePathRelative:"docker/docker-compose-command.md",git:{updatedTime:1626154667e3,contributors:[]}}},1475:(e,n,s)=>{"use strict";s.r(n),s.d(n,{default:()=>l});const a=(0,s(6252).uE)('<p>模板文件是使用 Compose 的核心，涉及到的指令关键字也比较多。但大家不用担心，这里面大部分指令跟 docker run 相关参数的含义都是类似的。</p><p>默认的模板文件名称为 docker-compose.yml，格式为 YAML 格式。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &quot;3&quot;\n\nservices:\n  webapp:\n    image: examples/web\n    ports:\n      - &quot;80:80&quot;\n    volumes:\n      - &quot;/data&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>注意每个服务都必须通过 image 指令指定镜像或 build 指令（需要 Dockerfile）等来自动构建生成镜像。 如果使用 build 指令，在 Dockerfile 中设置的选项(例如：CMD, EXPOSE, VOLUME, ENV 等) 将会自动被获取，无需在 docker-compose.yml 中再次设置。</p><p>下面分别介绍各个指令的用法。</p><h2 id="build" tabindex="-1"><a class="header-anchor" href="#build" aria-hidden="true">#</a> build</h2><p>指定 Dockerfile 所在文件夹的路径（可以是绝对路径，或者相对 docker-compose.yml 文件的路径）。 Compose 将会利用它自动构建这个镜像，然后使用这个镜像。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3&#39;\nservices:\n\n  webapp:\n    build: ./dir\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>你也可以使用 context 指令指定 Dockerfile 所在文件夹的路径。 使用 dockerfile 指令指定 Dockerfile 文件名。 使用 arg 指令指定构建镜像时的变量。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3&#39;\nservices:\n\n  webapp:\n    build:\n      context: ./dir\n      dockerfile: Dockerfile-alternate\n      args:\n        buildno: 1\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>使用 cache_from 指定构建镜像的缓存</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>build:\n  context: .\n  cache_from:\n    - alpine:latest\n    - corp/web_app:3.14\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="cap-add-cap-drop" tabindex="-1"><a class="header-anchor" href="#cap-add-cap-drop" aria-hidden="true">#</a> cap_add, cap_drop</h2><p>指定容器的内核能力（capacity）分配。</p><p>例如，让容器拥有所有能力可以指定为：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>cap_add:\n  - ALL\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>去掉 NET_ADMIN 能力可以指定为：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>cap_drop:\n  - NET_ADMIN\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="command" tabindex="-1"><a class="header-anchor" href="#command" aria-hidden="true">#</a> command</h2><p>覆盖容器启动后默认执行的命令。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>command: echo &quot;hello world&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="configs" tabindex="-1"><a class="header-anchor" href="#configs" aria-hidden="true">#</a> configs</h2><p>仅用于 Swarm mode</p><h2 id="cgroup-parent" tabindex="-1"><a class="header-anchor" href="#cgroup-parent" aria-hidden="true">#</a> cgroup_parent</h2><p>指定父 cgroup 组，意味着将继承该组的资源限制。</p><p>例如，创建了一个 cgroup 组名称为 cgroups_1。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>cgroup_parent: cgroups_1\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="container-name" tabindex="-1"><a class="header-anchor" href="#container-name" aria-hidden="true">#</a> container_name</h2><p>指定容器名称。默认将会使用 项目名称_服务名称_序号 这样的格式。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>container_name: docker-web-container\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>注意: 指定容器名称后，该服务将无法进行扩展（scale），因为 Docker 不允许多个容器具有相同的名称。</p><h2 id="deploy" tabindex="-1"><a class="header-anchor" href="#deploy" aria-hidden="true">#</a> deploy</h2><p>仅用于 Swarm mode</p><h2 id="devices" tabindex="-1"><a class="header-anchor" href="#devices" aria-hidden="true">#</a> devices</h2><p>指定设备映射关系。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>devices:\n  - &quot;/dev/ttyUSB1:/dev/ttyUSB0&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="depends-on" tabindex="-1"><a class="header-anchor" href="#depends-on" aria-hidden="true">#</a> depends_on</h2><p>解决容器的依赖、启动先后的问题。以下例子中会先启动 redis db 再启动 web</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3&#39;\n\nservices:\n  web:\n    build: .\n    depends_on:\n      - db\n      - redis\n\n  redis:\n    image: redis\n\n  db:\n    image: postgres\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>注意：web 服务不会等待 redis db 「完全启动」之后才启动。</p><h2 id="dns" tabindex="-1"><a class="header-anchor" href="#dns" aria-hidden="true">#</a> dns</h2><p>自定义 DNS 服务器。可以是一个值，也可以是一个列表。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>dns: 8.8.8.8\n\ndns:\n  - 8.8.8.8\n  - 114.114.114.114\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="dns-search" tabindex="-1"><a class="header-anchor" href="#dns-search" aria-hidden="true">#</a> dns_search</h2><p>配置 DNS 搜索域。可以是一个值，也可以是一个列表。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>dns_search: example.com\n\ndns_search:\n  - domain1.example.com\n  - domain2.example.com\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="tmpfs" tabindex="-1"><a class="header-anchor" href="#tmpfs" aria-hidden="true">#</a> tmpfs</h2><p>挂载一个 tmpfs 文件系统到容器。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>tmpfs: /run\ntmpfs:\n  - /run\n  - /tmp\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="env-file" tabindex="-1"><a class="header-anchor" href="#env-file" aria-hidden="true">#</a> env_file</h2><p>从文件中获取环境变量，可以为单独的文件路径或列表。</p><p>如果通过 docker-compose -f FILE 方式来指定 Compose 模板文件，则 env_file 中变量的路径会基于模板文件路径。</p><p>如果有变量名称与 environment 指令冲突，则按照惯例，以后者为准。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>env_file: .env\n\nenv_file:\n  - ./common.env\n  - ./apps/web.env\n  - /opt/secrets.env\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>环境变量文件中每一行必须符合格式，支持 # 开头的注释行。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code># common.env: Set development environment\nPROG_ENV=development\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="environment" tabindex="-1"><a class="header-anchor" href="#environment" aria-hidden="true">#</a> environment</h2><p>设置环境变量。你可以使用数组或字典两种格式。</p><p>只给定名称的变量会自动获取运行 Compose 主机上对应变量的值，可以用来防止泄露不必要的数据。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>environment:\n  RACK_ENV: development\n  SESSION_SECRET:\n\nenvironment:\n  - RACK_ENV=development\n  - SESSION_SECRET\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如果变量名称或者值中用到 true|false，yes|no 等表达 布尔 含义的词汇，最好放到引号里，避免 YAML 自动解析某些内容为对应的布尔语义。这些特定词汇，包括</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>y|Y|yes|Yes|YES|n|N|no|No|NO|true|True|TRUE|false|False|FALSE|on|On|ON|off|Off|OFF\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="expose" tabindex="-1"><a class="header-anchor" href="#expose" aria-hidden="true">#</a> expose</h2><p>暴露端口，但不映射到宿主机，只被连接的服务访问。 仅可以指定内部端口为参数</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>expose:\n - &quot;3000&quot;\n - &quot;8000&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="external-links" tabindex="-1"><a class="header-anchor" href="#external-links" aria-hidden="true">#</a> external_links</h2><p><s>注意：不建议使用该指令。</s> 链接到 docker-compose.yml 外部的容器，甚至并非 Compose 管理的外部容器。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>external_links:\n - redis_1\n - project_db_1:mysql\n - project_db_1:postgresql\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="extra-hosts" tabindex="-1"><a class="header-anchor" href="#extra-hosts" aria-hidden="true">#</a> extra_hosts</h2><p>类似 Docker 中的 --add-host 参数，指定额外的 host 名称映射信息。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>extra_hosts:\n - &quot;googledns:8.8.8.8&quot;\n - &quot;dockerhub:52.1.157.61&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>会在启动后的服务容器中 /etc/hosts 文件中添加如下两条条目。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>8.8.8.8 googledns\n52.1.157.61 dockerhub\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="healthcheck" tabindex="-1"><a class="header-anchor" href="#healthcheck" aria-hidden="true">#</a> healthcheck</h2><p>通过命令检查容器是否健康运行。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>healthcheck:\n  test: [&quot;CMD&quot;, &quot;curl&quot;, &quot;-f&quot;, &quot;http://localhost&quot;]\n  interval: 1m30s\n  timeout: 10s\n  retries: 3\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="image" tabindex="-1"><a class="header-anchor" href="#image" aria-hidden="true">#</a> image</h2><p>指定为镜像名称或镜像 ID。如果镜像在本地不存在，Compose 将会尝试拉取这个镜像。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>image: ubuntu\nimage: orchardup/postgresql\nimage: a4bc65fd\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="labels" tabindex="-1"><a class="header-anchor" href="#labels" aria-hidden="true">#</a> labels</h2><p>为容器添加 Docker 元数据（metadata）信息。例如可以为容器添加辅助说明信息。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>labels:\n  com.startupteam.description: &quot;webapp for a startup team&quot;\n  com.startupteam.department: &quot;devops department&quot;\n  com.startupteam.release: &quot;rc3 for v1.0&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="links" tabindex="-1"><a class="header-anchor" href="#links" aria-hidden="true">#</a> links</h2><p><s>注意：不推荐使用该指令。</s></p><h2 id="logging" tabindex="-1"><a class="header-anchor" href="#logging" aria-hidden="true">#</a> logging</h2><p>配置日志选项。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>logging:\n  driver: syslog\n  options:\n    syslog-address: &quot;tcp://192.168.0.42:123&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>目前支持三种日志驱动类型。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>driver: &quot;json-file&quot;\ndriver: &quot;syslog&quot;\ndriver: &quot;none&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>options 配置日志驱动的相关参数。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>options:\n  max-size: &quot;200k&quot;\n  max-file: &quot;10&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="network-mode" tabindex="-1"><a class="header-anchor" href="#network-mode" aria-hidden="true">#</a> network_mode</h2><p>设置网络模式。使用和 docker run 的 --network 参数一样的值。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>network_mode: &quot;bridge&quot;\nnetwork_mode: &quot;host&quot;\nnetwork_mode: &quot;none&quot;\nnetwork_mode: &quot;service:[service name]&quot;\nnetwork_mode: &quot;container:[container name/id]&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="networks" tabindex="-1"><a class="header-anchor" href="#networks" aria-hidden="true">#</a> networks</h2><p>配置容器连接的网络。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &quot;3&quot;\nservices:\n\n  some-service:\n    networks:\n     - some-network\n     - other-network\n\nnetworks:\n  some-network:\n  other-network:\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="pid" tabindex="-1"><a class="header-anchor" href="#pid" aria-hidden="true">#</a> pid</h2><p>跟主机系统共享进程命名空间。打开该选项的容器之间，以及容器和宿主机系统之间可以通过进程 ID 来相互访问和操作。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>pid: &quot;host&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="ports" tabindex="-1"><a class="header-anchor" href="#ports" aria-hidden="true">#</a> ports</h2><p>暴露端口信息。 使用宿主端口：容器端口 (HOST:CONTAINER) 格式，或者仅仅指定容器的端口（宿主将会随机选择端口）都可以。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>ports:\n - &quot;3000&quot;\n - &quot;8000:8000&quot;\n - &quot;49100:22&quot;\n - &quot;127.0.0.1:8001:8001&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>注意：当使用 HOST:CONTAINER 格式来映射端口时，如果你使用的容器端口小于 60 并且没放到引号里，可能会得到错误结果，因为 YAML 会自动解析 xx:yy 这种数字格式为 60 进制。为避免出现这种问题，建议数字串都采用引号包括起来的字符串格式。</p><h2 id="secrets" tabindex="-1"><a class="header-anchor" href="#secrets" aria-hidden="true">#</a> secrets</h2><p>存储敏感数据，例如 mysql 服务密码。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &quot;3.1&quot;\nservices:\n\nmysql:\n image: mysql\n environment:\n   MYSQL_ROOT_PASSWORD_FILE: /run/secrets/db_root_password\n secrets:\n   - db_root_password\n   - my_other_secret\n\nsecrets:\n my_secret:\n   file: ./my_secret.txt\n my_other_secret:\n   external: true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h2 id="security-opt" tabindex="-1"><a class="header-anchor" href="#security-opt" aria-hidden="true">#</a> security_opt</h2><p>指定容器模板标签（label）机制的默认属性（用户、角色、类型、级别等）。例如配置标签的用户名和角色名。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>security_opt:\n    - label:user:USER\n    - label:role:ROLE\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="stop-signal" tabindex="-1"><a class="header-anchor" href="#stop-signal" aria-hidden="true">#</a> stop_signal</h2><p>设置另一个信号来停止容器。在默认情况下使用的是 SIGTERM 停止容器。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>stop_signal: SIGUSR1\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="sysctls" tabindex="-1"><a class="header-anchor" href="#sysctls" aria-hidden="true">#</a> sysctls</h2><p>配置容器内核参数。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>sysctls:\n  net.core.somaxconn: 1024\n  net.ipv4.tcp_syncookies: 0\n\nsysctls:\n  - net.core.somaxconn=1024\n  - net.ipv4.tcp_syncookies=0\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="ulimits" tabindex="-1"><a class="header-anchor" href="#ulimits" aria-hidden="true">#</a> ulimits</h2><p>指定容器的 ulimits 限制值。</p><p>例如，指定最大进程数为 65535，指定文件句柄数为 20000（软限制，应用可以随时修改，不能超过硬限制） 和 40000（系统硬限制，只能 root 用户提高）。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>  ulimits:\n    nproc: 65535\n    nofile:\n      soft: 20000\n      hard: 40000\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="volumes" tabindex="-1"><a class="header-anchor" href="#volumes" aria-hidden="true">#</a> volumes</h2><p>数据卷所挂载路径设置。可以设置宿主机路径 （HOST:CONTAINER） 或加上访问模式 （HOST:CONTAINER:ro）。 该指令中路径支持相对路径。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>volumes:\n - /var/lib/mysql\n - cache/:/tmp/cache\n - ~/configs:/etc/configs/:ro\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="其它指令" tabindex="-1"><a class="header-anchor" href="#其它指令" aria-hidden="true">#</a> 其它指令</h2><p>此外，还有包括 domainname, entrypoint, hostname, ipc, mac_address, privileged, read_only, shm_size, restart, stdin_open, tty, user, working_dir 等指令，基本跟 docker run 中对应参数的功能一致。</p><p>指定服务容器启动后执行的入口文件。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>entrypoint: /code/entrypoint.sh\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>指定容器中运行应用的用户名。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>user: nginx\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>指定容器中工作目录。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>working_dir: /code\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>指定容器中搜索域名、主机名、mac 地址等。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>domainname: your_website.com\nhostname: test\nmac_address: 08-00-27-00-0C-0A\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>允许容器中运行一些特权命令。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>privileged: true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>指定容器退出后的重启策略为始终重启。该命令对保持服务始终运行十分有效，在生产环境中推荐配置为 always 或者 unless-stopped。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>restart: always\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>以只读模式挂载容器的 root 文件系统，意味着不能对容器内容进行修改。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>read_only: true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>打开标准输入，可以接受外部输入。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>stdin_open: true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>模拟一个伪终端。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>tty: true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="读取变量" tabindex="-1"><a class="header-anchor" href="#读取变量" aria-hidden="true">#</a> 读取变量</h2><p>Compose 模板文件支持动态读取主机的系统环境变量和当前目录下的 .env 文件中的变量。</p><p>例如，下面的 Compose 文件将从运行它的环境中读取变量 ${MONGO_VERSION} 的值，并写入执行的指令中。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &quot;3&quot;\nservices:\n\ndb:\n  image: &quot;mongo:${MONGO_VERSION}&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果执行 MONGO_VERSION=3.2 docker-compose up 则会启动一个 mongo:3.2 镜像的容器；如果执行 MONGO_VERSION=2.8 docker-compose up 则会启动一个 mongo:2.8 镜像的容器。</p><p>若当前目录存在 .env 文件，执行 docker-compose 命令时将从该文件中读取变量。</p><p>在当前目录新建 .env 文件并写入以下内容。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code># 支持 # 号注释\nMONGO_VERSION=3.6\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>执行 docker-compose up 则会启动一个 mongo:3.6 镜像的容器。</p><h2 id="常用软件docker-compose文件" tabindex="-1"><a class="header-anchor" href="#常用软件docker-compose文件" aria-hidden="true">#</a> 常用软件docker-compose文件</h2><h3 id="tomcat" tabindex="-1"><a class="header-anchor" href="#tomcat" aria-hidden="true">#</a> Tomcat</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  tomcat:\n    restart: always\n    image: tomcat\n    container_name: tomcat\n    ports:\n      - 8080:8080\n    volumes:\n      - /usr/local/docker/tomcat/webapps/test:/usr/local/tomcat/webapps/test\n    environment:\n      TZ: Asia/Shanghai\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="mysql5" tabindex="-1"><a class="header-anchor" href="#mysql5" aria-hidden="true">#</a> Mysql5</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  mysql:\n    restart: always\n    image: mysql:5.7.22\n    container_name: mysql\n    ports:\n      - 3306:3306\n    environment:\n      TZ: Asia/Shanghai\n      MYSQL_ROOT_PASSWORD: 123456\n    command:\n      --character-set-server=utf8mb4\n      --collation-server=utf8mb4_general_ci\n      --explicit_defaults_for_timestamp=true\n      --lower_case_table_names=1\n      --max_allowed_packet=128M\n      --sql-mode=&quot;STRICT_TRANS_TABLES,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION,NO_ZERO_DATE,NO_ZERO_IN_DATE,ERROR_FOR_DIVISION_BY_ZERO&quot;\n    volumes:\n      - mysql-data:/var/lib/mysql\n\nvolumes:\n  mysql-data:\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h3 id="mysql8" tabindex="-1"><a class="header-anchor" href="#mysql8" aria-hidden="true">#</a> Mysql8</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  db:\n    image: mysql\n    restart: always\n    environment:\n      MYSQL_ROOT_PASSWORD: 123456\n    command:\n      --default-authentication-plugin=mysql_native_password\n      --character-set-server=utf8mb4\n      --collation-server=utf8mb4_general_ci\n      --explicit_defaults_for_timestamp=true\n      --lower_case_table_names=1\n    ports:\n      - 3306:3306\n    volumes:\n      - ./data:/var/lib/mysql\n\n  adminer:\n    image: adminer\n    restart: always\n    ports:\n      - 8080:8080\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h3 id="redis集群" tabindex="-1"><a class="header-anchor" href="#redis集群" aria-hidden="true">#</a> Redis集群</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  master:\n    image: redis\n    container_name: redis-master\n    ports:\n      - 6379:6379\n\n  slave1:\n    image: redis\n    container_name: redis-slave-1\n    ports:\n      - 6380:6379\n    command: redis-server --slaveof redis-master 6379\n\n  slave2:\n    image: redis\n    container_name: redis-slave-2\n    ports:\n      - 6381:6379\n    command: redis-server --slaveof redis-master 6379\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="sentinel集群" tabindex="-1"><a class="header-anchor" href="#sentinel集群" aria-hidden="true">#</a> Sentinel集群</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  sentinel1:\n    image: redis\n    container_name: redis-sentinel-1\n    ports:\n      - 26379:26379\n    command: redis-sentinel /usr/local/etc/redis/sentinel.conf\n    volumes:\n      - ./sentinel1.conf:/usr/local/etc/redis/sentinel.conf\n\n  sentinel2:\n    image: redis\n    container_name: redis-sentinel-2\n    ports:\n      - 26380:26379\n    command: redis-sentinel /usr/local/etc/redis/sentinel.conf\n    volumes:\n      - ./sentinel2.conf:/usr/local/etc/redis/sentinel.conf\n\n  sentinel3:\n    image: redis\n    container_name: redis-sentinel-3\n    ports:\n      - 26381:26379\n    command: redis-sentinel /usr/local/etc/redis/sentinel.conf\n    volumes:\n      - ./sentinel3.conf:/usr/local/etc/redis/sentinel.conf\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br></div></div><p>修改 Sentinel 配置文件</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>port 26379\ndir /tmp\n# 自定义集群名，其中 127.0.0.1 为 redis-master 的 ip，6379 为 redis-master 的端口，2 为最小投票数（因为有 3 台 Sentinel 所以可以设置成 2）\nsentinel monitor mymaster 127.0.0.1 6379 2\nsentinel down-after-milliseconds mymaster 30000\nsentinel parallel-syncs mymaster 1\nsentinel failover-timeout mymaster 180000\nsentinel deny-scripts-reconfig yes\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="jenkins" tabindex="-1"><a class="header-anchor" href="#jenkins" aria-hidden="true">#</a> Jenkins</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  jenkins:\n    restart: always\n    image: jenkinsci/jenkins\n    container_name: jenkins\n    ports:\n      # 发布端口\n      - 8080:8080\n      # 基于 JNLP 的 Jenkins 代理通过 TCP 端口 50000 与 Jenkins master 进行通信\n      - 50000:50000\n    environment:\n      TZ: Asia/Shanghai\n    volumes:\n      - ./data:/var/jenkins_home\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>安装过程中会出现 Docker 数据卷 权限问题，用以下命令解决：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>chown -R 1000 /usr/local/docker/jenkins/data\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',169),l={render:function(e,n){return a}}}}]);